{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        using var transaction = db.Database.BeginTransaction();
        db.Database.Migrate();
        transaction.Commit();
    });
}

arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    // EF Core 9 wraps each migration in its own transaction;
    // a manual outer transaction is no longer needed and would throw.
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        db.Database.Migrate();
    });
}

